        ("architecture","03","Architecture", card('<pre>Turn -> Scratchpad -> [if tokens > budget] Summarize -> Long-term store (embed)\nQuery -> Retrieve relevant memories -> Inject into system prompt</pre>')),
        ("scratchpad","04","Deep Dive: Scratchpad", card("<p>Working memory: thoughts, tool JSON, observations. Truncate old observations; keep last 3 tool results full.</p>")),
        ("longterm","05","Deep Dive: Long-Term Vector Memory", diag("agent-memory","vector-zoom","User facts embedded and stored in vector DB; retrieved by query similarity at session start") + card("<p>Mem0, Zep, custom pgvector. Store extracted facts not raw chat. user_id namespace isolation.</p>")),
