        ("retrieval","08","Deep Dive: Memory Retrieval", card("<p>At session start: embed user message, search memory top-5, inject as system context. Re-rank by recency × relevance.</p>")),
        ("production","09","Production & Ops", card("<ul><li>GDPR delete by user_id across memory stores</li><li>Don't store secrets/PII without encryption</li><li>Memory write audit log</li></ul>")),
